/**
 * Server-only module for accessing the transactions SQLite database.
 *
 * This module imports `better-sqlite3` (a native Node addon) and must never
 * be imported from client-side code. It is only consumed from Qwik City
 * route loaders and request handlers, which are server-only boundaries.
 */
import Database from "better-sqlite3";
import { resolve } from "node:path";

export interface Transaction {
  id: number;
  date: string;
  category: string;
  description: string;
  amount: number;
}

export interface TransactionFilters {
  from?: string;
  to?: string;
  category?: string;
}

let dbInstance: Database.Database | null = null;

function getDb(): Database.Database {
  if (!dbInstance) {
    const dbPath = resolve(process.cwd(), "data", "reports.db");
    dbInstance = new Database(dbPath, { readonly: true });
  }
  return dbInstance;
}

/**
 * Returns the transactions matching the provided filters, ordered by `id`
 * ascending. Filters are combined with logical AND:
 *  - `from`:     date >= from  (inclusive)
 *  - `to`:       date <= to    (inclusive)
 *  - `category`: category == category (exact, case-sensitive)
 */
export function getTransactions(filters: TransactionFilters): Transaction[] {
  const conditions: string[] = [];
  const params: Record<string, string> = {};

  if (filters.from) {
    conditions.push("date >= :from");
    params.from = filters.from;
  }
  if (filters.to) {
    conditions.push("date <= :to");
    params.to = filters.to;
  }
  if (filters.category) {
    conditions.push("category = :category");
    params.category = filters.category;
  }

  const where =
    conditions.length > 0 ? `WHERE ${conditions.join(" AND ")}` : "";
  const sql = `SELECT id, date, category, description, amount
               FROM transactions
               ${where}
               ORDER BY id ASC`;

  return getDb().prepare(sql).all(params) as Transaction[];
}

/**
 * Escapes a single field for RFC 4180 CSV. If the field contains a comma,
 * double quote, or newline, it is wrapped in double quotes and any inner
 * double quotes are doubled.
 */
function escapeCsvField(value: string): string {
  const needsQuoting = /[",\r\n]/.test(value);
  if (needsQuoting) {
    return `"${value.replace(/"/g, '""')}"`;
  }
  return value;
}

/**
 * Serializes an array of transactions into a RFC 4180 compliant CSV string.
 * - Header row: id,date,category,description,amount
 * - Records separated by CRLF (\r\n)
 * - amount written as its plain numeric value
 */
export function transactionsToCsv(transactions: Transaction[]): string {
  const header = "id,date,category,description,amount";
  const lines = [header];

  for (const t of transactions) {
    const row = [
      String(t.id),
      escapeCsvField(t.date),
      escapeCsvField(t.category),
      escapeCsvField(t.description),
      String(t.amount),
    ].join(",");
    lines.push(row);
  }

  return lines.join("\r\n");
}

import { component$ } from "@builder.io/qwik";
import {
  routeLoader$,
  type DocumentHead,
} from "@builder.io/qwik-city";
import {
  getTransactions,
  type TransactionFilters,
} from "~/server/transactions";

/**
 * Server-only route loader. Reads the current filter values from the URL
 * query string and queries the SQLite database for matching transactions.
 * The result is serialized into the initial server-rendered HTML.
 */
export const useTransactions = routeLoader$(async (event) => {
  const from = event.query.get("from") || undefined;
  const to = event.query.get("to") || undefined;
  const category = event.query.get("category") || undefined;

  const filters: TransactionFilters = {};
  if (from) filters.from = from;
  if (to) filters.to = to;
  if (category) filters.category = category;

  return getTransactions(filters);
});

/**
 * Builds the export endpoint URL carrying the exact same filter values that
 * are currently applied to the page.
 */
function buildExportHref(filters: TransactionFilters): string {
  const params = new URLSearchParams();
  if (filters.from) params.set("from", filters.from);
  if (filters.to) params.set("to", filters.to);
  if (filters.category) params.set("category", filters.category);
  const qs = params.toString();
  return qs ? `/reports/export?${qs}` : "/reports/export";
}

export default component$(() => {
  const transactions = useTransactions();

  // Reconstruct the active filters from the loader data is not possible
  // (loader only returns rows), so read them from the current location query.
  // The useLocation hook gives us client-side access to the URL.
  const from = useLocQuery("from");
  const to = useLocQuery("to");
  const category = useLocQuery("category");

  const filters: TransactionFilters = {};
  if (from) filters.from = from;
  if (to) filters.to = to;
  if (category) filters.category = category;

  const exportHref = buildExportHref(filters);

  return (
    <div>
      <h1>Expense Reports</h1>

      <p>
        <a href={exportHref}>Download CSV</a>
      </p>

      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>Date</th>
            <th>Category</th>
            <th>Description</th>
            <th>Amount</th>
          </tr>
        </thead>
        <tbody>
          {transactions.value.map((t) => (
            <tr key={t.id}>
              <td>{t.id}</td>
              <td>{t.date}</td>
              <td>{t.category}</td>
              <td>{t.description}</td>
              <td>{t.amount}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
});

/**
 * Small helper that reads a single query parameter from the current location
 * on the client. Returns an empty string when the parameter is absent.
 */
function useLocQuery(name: string): string {
  // This runs during SSR and on the client; useLocation is available in both.
  // We import lazily to avoid a circular dependency at module top-level.
  // eslint-disable-next-line @typescript-eslint/no-var-requires
  const { useLocation } = require("@builder.io/qwik-city");
  const loc = useLocation();
  return loc.url.searchParams.get(name) || "";
}

export const head: DocumentHead = {
  title: "Expense Reports",
};

import { component$ } from "@builder.io/qwik";
import { routeLoader$, type DocumentHead } from "@builder.io/qwik-city";
import {
  getTransactions,
  type Transaction,
  type TransactionFilters,
} from "~/server/transactions";

interface ReportData {
  rows: Transaction[];
  filters: TransactionFilters;
}

/**
 * Server-only route loader. Reads the current filter values from the URL
 * query string and queries the SQLite database for matching transactions.
 * Both the rows and the active filters are serialized into the initial
 * server-rendered HTML so the page can render the descriptions and build a
 * "Download CSV" link carrying the exact same filter values.
 */
export const useReport = routeLoader$(async (event): Promise<ReportData> => {
  const from = event.query.get("from") || undefined;
  const to = event.query.get("to") || undefined;
  const category = event.query.get("category") || undefined;

  const filters: TransactionFilters = {};
  if (from) filters.from = from;
  if (to) filters.to = to;
  if (category) filters.category = category;

  const rows = getTransactions(filters);
  return { rows, filters };
});

/**
 * Builds the export endpoint URL carrying the exact same filter values that
 * are currently applied to the page.
 */
function buildExportHref(filters: TransactionFilters): string {
  const params = new URLSearchParams();
  if (filters.from) params.set("from", filters.from);
  if (filters.to) params.set("to", filters.to);
  if (filters.category) params.set("category", filters.category);
  const qs = params.toString();
  return qs ? `/reports/export?${qs}` : "/reports/export";
}

export default component$(() => {
  const report = useReport();
  const { rows, filters } = report.value;
  const exportHref = buildExportHref(filters);

  return (
    <div>
      <h1>Expense Reports</h1>

      <p>
        <a href={exportHref}>Download CSV</a>
      </p>

      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>Date</th>
            <th>Category</th>
            <th>Description</th>
            <th>Amount</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((t) => (
            <tr key={t.id}>
              <td>{t.id}</td>
              <td>{t.date}</td>
              <td>{t.category}</td>
              <td>{t.description}</td>
              <td>{t.amount}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
});

export const head: DocumentHead = {
  title: "Expense Reports",
};

import type { RequestHandler } from "@builder.io/qwik-city";
import {
  getTransactions,
  transactionsToCsv,
  type TransactionFilters,
} from "~/server/transactions";

/**
 * CSV export endpoint.
 *
 * Applies the same `from`, `to`, and `category` query-parameter filters as the
 * report page (identical semantics) and streams the matching rows as a
 * downloadable RFC 4180 CSV file.
 */
export const onGet: RequestHandler = async (event) => {
  const from = event.query.get("from") || undefined;
  const to = event.query.get("to") || undefined;
  const category = event.query.get("category") || undefined;

  const filters: TransactionFilters = {};
  if (from) filters.from = from;
  if (to) filters.to = to;
  if (category) filters.category = category;

  const rows = getTransactions(filters);
  const csv = transactionsToCsv(rows);

  const headers = event.headers;
  headers.set("Content-Type", "text/csv; charset=utf-8");
  headers.set(
    "Content-Disposition",
    'attachment; filename="transactions.csv"',
  );

  // CRLF line endings are part of the CSV body itself; send the raw bytes.
  event.send(new TextEncoder().encode(csv));
};

